import React, { useState, useEffect } from "react";

// Screens
import SplashScreen from "./screens/SplashScreen.jsx";
import SignInScreen from "./screens/SignInScreen.jsx";
import SignUpScreen from "./screens/SignUpScreen.jsx";
import HomeScreen from "./screens/HomeScreen.jsx";
import GoalsScreen from "./screens/GoalsScreen.jsx";
import LoansScreen from "./screens/LoansScreen.jsx";
import ProfileScreen from "./screens/ProfileScreen.jsx";
import DepositScreen from "./screens/DepositScreen.jsx";
import WithdrawScreen from "./screens/WithdrawScreen.jsx";
import SavingsDepositScreen from "./screens/SavingsDepositScreen.jsx";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawScreen.jsx";
import TransactionHistoryScreen from "./screens/TransactionHistoryScreen.jsx";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen.jsx";

// Icons
import { Home, Target, CreditCard, User } from "lucide-react";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Splash");
  const [tab, setTab] = useState("Home");

  // Mock user & data
  const [user] = useState({
    name: "Faith Bode",
    email: "faith@example.com",
    joinedDate: "Jan 2025",
  });

  const [balance, setBalance] = useState(1500);
  const [savingsBalance, setSavingsBalance] = useState(300);
  const [goals] = useState([
    { id: 1, title: "Buy PS5", description: "Save for PS5 console", amountSaved: 100, targetAmount: 500 },
  ]);
  const [loans] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);

  // Splash → SignIn
  useEffect(() => {
    const timer = setTimeout(() => setCurrentScreen("SignIn"), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Transaction handlers
  const handleDeposit = (amount) => {
    const tx = { id: Date.now(), type: "deposit", title: "Deposit", amount, date: new Date().toLocaleDateString() };
    setBalance((prev) => prev + amount);
    setTransactions((prev) => [tx, ...prev]);
    setSelectedTransaction(tx);
    setCurrentScreen("TransactionReceipt");
  };

  const handleWithdraw = (amount) => {
    const tx = { id: Date.now(), type: "withdraw", title: "Withdrawal", amount, date: new Date().toLocaleDateString() };
    setBalance((prev) => prev - amount);
    setTransactions((prev) => [tx, ...prev]);
    setSelectedTransaction(tx);
    setCurrentScreen("TransactionReceipt");
  };

  const handleSavingsDeposit = (amount) => {
    const tx = { id: Date.now(), type: "savings", title: "Savings Deposit", amount, date: new Date().toLocaleDateString() };
    setBalance((prev) => prev - amount);
    setSavingsBalance((prev) => prev + amount);
    setTransactions((prev) => [tx, ...prev]);
    setSelectedTransaction(tx);
    setCurrentScreen("TransactionReceipt");
  };

  const handleSavingsWithdraw = (amount) => {
    const tx = { id: Date.now(), type: "savings-withdraw", title: "Savings Withdrawal", amount, date: new Date().toLocaleDateString() };
    setBalance((prev) => prev + amount);
    setSavingsBalance((prev) => prev - amount);
    setTransactions((prev) => [tx, ...prev]);
    setSelectedTransaction(tx);
    setCurrentScreen("TransactionReceipt");
  };

  // Navigation helpers
  const goBack = () => {
    if (currentScreen === "TransactionReceipt") setCurrentScreen("Transactions");
    else setCurrentScreen("Dashboard");
  };

  const openReceipt = (tx) => {
    setSelectedTransaction(tx);
    setCurrentScreen("TransactionReceipt");
  };

  // Render screens
  const renderScreen = () => {
    switch (currentScreen) {
      case "Splash": return <SplashScreen onFinish={() => setCurrentScreen("SignIn")} />;
      case "SignIn": return <SignInScreen onSignIn={() => setCurrentScreen("Dashboard")} />;
      case "SignUp": return <SignUpScreen onSignUp={() => setCurrentScreen("Dashboard")} />;
      case "Deposit": return <DepositScreen onDeposit={handleDeposit} goBack={goBack} />;
      case "Withdraw": return <WithdrawScreen onWithdraw={handleWithdraw} balance={balance} goBack={goBack} />;
      case "SavingsDeposit": return <SavingsDepositScreen onDeposit={handleSavingsDeposit} savingsBalance={savingsBalance} goBack={goBack} />;
      case "SavingsWithdraw": return <SavingsWithdrawScreen onWithdraw={handleSavingsWithdraw} savingsBalance={savingsBalance} goBack={goBack} />;
      case "Transactions": return <TransactionHistoryScreen transactions={transactions} goBack={goBack} openReceipt={openReceipt} />;
      case "TransactionReceipt": return <TransactionReceiptScreen transaction={selectedTransaction} goBack={goBack} />;
      case "Dashboard":
      default:
        switch (tab) {
          case "Home":
            return <HomeScreen balance={balance} savingsBalance={savingsBalance} transactions={transactions} userName={user.name} openScreen={setCurrentScreen} />;
          case "Goals": return <GoalsScreen goals={goals} />;
          case "Loans": return <LoansScreen loans={loans} />;
          case "Profile": return <ProfileScreen user={user} />;
          default: return null;
        }
    }
  };

  const tabs = [
    { key: "Home", label: "Home", icon: Home },
    { key: "Goals", label: "Goals", icon: Target },
    { key: "Loans", label: "Loans", icon: CreditCard },
    { key: "Profile", label: "Profile", icon: User },
  ];

  return (
    <div className="min-h-screen bg-gray-50 pb-24">
      {renderScreen()}

      {currentScreen === "Dashboard" && (
        <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-gray-200 flex">
          {tabs.map((t) => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={`flex-1 py-3 flex flex-col items-center ${
                tab === t.key ? "text-teal-600" : "text-gray-400"
              }`}
            >
              <t.icon size={22} />
              <span className="text-xs mt-1">{t.label}</span>
            </button>
          ))}
        </nav>
      )}
    </div>
  );
}
